VALUES
  ('heelevel3-6f0ba476-moex-00382', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年1月1日以$10,000買進乙公司30%之股權並取得重大影響力，乙公司的淨資 產為$40,000，而甲公司取得之股權份額之公允價值亦為$12,000。請問甲公司當日應增加「採 用權益法之投資」科目之金額為：', '["$3,000", "$10,000", "$12,000", "$40,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00383', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '下列有幾項資產分類為「待出售」後，不適用IFRS5號公報以「帳面金額與公允價值減出售', '["遞延所得稅資產", "由員工福利產生的資產", "不動產、廠房 及設備", "金融工具規範的金融資產 ⑤採用公允價值模式處理的投資性不動產 ⑥農業會 計採用公允價值減出售成本後餘額衡量的非流動資產"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00384', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司於110年初購入100頭3個月大之乳牛，每頭乳牛價格為$5,000與支付運費$20,000， 準備飼養成熟後生產牛奶。甲公司估計若立即將 100 頭乳牛出售，應支付送至市場之運費 $22,000 及市場管理規費$8,000。甲公司 110 年間耗費草料費用$120,000，人工飼育成本 $130,000，公司將後續支出作為費用處理。110年底公司估計若將100頭乳牛立即出售，每頭 售價為$10,000，另應支付運送牛隻至市場之運費$32,000及市場管理規費等$8,000，則甲公司 110年上述交易與年底評價相關分錄與科目何者正確？', '["購入乳牛時，應借記「生產性生物資產」$480,000", "購入乳牛時，應借記「公允價值減出售成本之變動損益」$20,000", "年底「公允價值減出售成本之變動損益」貸方餘額$440,000", "年底評價時應貸記「公允價值減出售成本之變動損益」$510,000 32270"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00385', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司經營家電用品產銷業務，其銷售的電冰箱均附有一年的售後服務保證，顧客購買冰箱 後，在一年內如因製造瑕疵而發生故障，均由甲公司免費更換零件及維修，重大瑕疵則由甲 公司更換新電冰箱。根據經驗，電冰箱如發生製造小瑕疵，平均一台維修費用（連工帶料） 約為$1,875，如為大瑕疵，平均一台損失大約$3,750。甲公司110年共銷售電冰箱100,000台， 根據過去經驗，大約有4%會發生小瑕疵，1%會發生大瑕疵。請問110年12月31日產品服 務保證負債準備金額為多少？', '["$7,500,000", "$8,850,000", "$9,000,000", "$11,250,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00386', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司110年初發行面額$15,000,000的公司債流通在外，票面利率6%，10年期，每年6月 30日及12月31日付息，折價發行，於110年6月30日付息（並攤銷折價）後，其帳面金 額為$14,700,000。當日甲公司以98的價格從公開市場買回面額$3,750,000的公司債註銷，付 手續費$2,970。請問110年6月30日買回分錄，下列敘述何者正確？', '["借方「應付公司債折價」$75,000", "貸方「現金」$3,675,000", "借方「償債損益」$2,970", "貸方「應付公司債折價」$70,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00387', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司新進會計人員使用間接法編製現金流量表，111 年相關資料如下：購買一台機器付款 $240,000，該年度有員工認股計畫認列薪資費用$72,000，採權益法之長期股權投資收到現金 股利$127,500，交易目的證券投資分類為「透過損益按公允價值衡量之金融資產」期末評價損 失$12,000，簽發票據$198,000取得一筆土地。111年度折舊費用$78,000，權益法認列投資收 益$202,500，發行公司債$300,000。111年度應收帳款淨額增加$90,000，應付帳款減少$78,000， 存貨減少$27,000。111年度淨利$82,500，期初現金餘額$63,000。請問甲公司111年之營業活 動現金流量最接近金額為何？（註：請將「股利收取」作為營業活動之交易）', '["流入$4,500", "流入$28,500", "流入$433,500", "流出$115,500"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00388', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司的淨利率為20%，總資產報酬率為20%，平均資產總額除以平均股東權益比為3，則 股東權益報酬率為何？', '["40%", "50%", "60%", "70%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00389', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'single_choice', '甲公司 110 年度各項收益有$2,000,000，各項費損$1,000,000。綜合損益表各項收益中有 $800,000無須在110年度報稅，但應在111年度報稅。假設110年度及111年度所得稅稅率 均為20%，請問甲公司110年度的「遞延所得稅負債」有多少？', '["$108,000", "$160,000", "$200,000", "$300,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00390', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'essay', '甲為原住民，登記為 A原住民保留地所有人，乙並非原住民，為經營民
宿，出資向甲購買 A地，之後並興建 B屋，為了擔保該出資並取得 B屋
的占有權源，乙從甲處取得 A地的抵押權、地上權後，再與原住民丙成
立借名登記契約，然後以丙的名義與甲簽訂 A地買賣契約，甲即將 A地
所有權移轉登記予丙。請問乙與丙間的借名登記契約、丙與甲間的買賣
契約、甲與乙間設定地上權行為及甲與丙間的所有權移轉登記行為效力
如何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00391', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'essay', '甲於民國 105 年 5 月 10 日與乙公司簽訂房屋土地買賣契約（下稱系爭
買賣契約），向乙公司購買坐落高雄市的土地及坐落其上 4 樓透天厝（下
合稱系爭房地）。甲已給付 4 成自備款，雙方約定其餘 6 成房價由乙公
司協助甲洽定提供金融機構的貸款給付，並於簽約時，將系爭買賣契約
第 18 條關於「貸款差額超過原預定貸款金額 30%，雙方均得解除契約」
（此為主管機關公告的定型化契約應記載事項及不得記載事項）的約定，
予以刪除，並各自用印、簽名。然乙公司所接洽的銀行均拒絕甲貸予該
6 成房價，甲依系爭買賣契約第 18條於 108 年 10月 20 日函知乙公司解
除系爭契約，乙公司依系爭買賣契約第25條第3項沒入買賣總價之15%
違約金。請問甲與乙公司合意刪除「貸款差額超過原預定貸款金額 30%
時，雙方均得解除契約」的約定，是否有效？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "e01a98800d61", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "1104", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
